export interface QuizQuestion {
  id: string;
  statement: string;
  isTrue: boolean;
  explanation: string;
}

export interface RelatedExamQuestion {
  id: string;
  sourceTitle: string;
  statement: string;
  isTrue: boolean;
  explanation: string;
  relatedPassage?: string;
  relatedModernText?: string;
  relatedCommentary?: string;
  relatedNarrativeSections?: NarrativeSection[];
  relatedCharacterMap?: CharacterMapData;
}

export interface CharacterRelation {
  from: string;
  to: string;
  type: "supporter" | "antagonist" | "family" | "neutral";
  label: string;
}

export interface CharacterMapData {
  characters: { name: string; role: string; description: string }[];
  relations: CharacterRelation[];
}

export type NarrativePhase =
  | "exposition"
  | "rising"
  | "climax"
  | "falling"
  | "resolution"
  | "발단"
  | "전개"
  | "위기"
  | "절정"
  | "결말"
  | "도입"
  | "전개 1"
  | "전개 2"
  | "절정/결말"
  | "기"
  | "승"
  | "전"
  | "결";

export interface NarrativeSection {
  phase: NarrativePhase;
  title: string;
  summary: string;
}

export type GrandUnit = "literature" | "non_fiction";

export interface QuizPassage {
  id: string;
  grandUnit: GrandUnit;
  categoryId: string;
  title: string;
  author: string;
  source: string;
  passage: string;
  originalText?: string;
  modernText?: string;
  commentary?: string;
  questions: QuizQuestion[];
  relatedExams?: RelatedExamQuestion[];
  narrativePhase?: NarrativePhase;
  narrativeSections?: NarrativeSection[];
  characterMap?: CharacterMapData;
}

